import { FIREBASE_CONFIG } from "../data/config";

/* ─── FIREBASE INITIALISER ──────────────────────────────────── */
/* Lazily loads Firebase v10 from CDN.
   Falls back to demo/mock mode if config is not yet filled in.  */
export const initFB = async () => {
  if (FIREBASE_CONFIG.apiKey === "YOUR_API_KEY") return null;
  try {
    const { initializeApp } = await import(
      "https://www.gstatic.com/firebasejs/10.7.1/firebase-app.js"
    );
    const {
      getAuth,
      signInWithEmailAndPassword,
      createUserWithEmailAndPassword,
    } = await import(
      "https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js"
    );
    const app  = initializeApp(FIREBASE_CONFIG);
    const auth = getAuth(app);
    return { auth, signInWithEmailAndPassword, createUserWithEmailAndPassword };
  } catch (e) {
    console.warn("Firebase init failed:", e.message);
    return null;
  }
};
